UPDATE ZML.DIM_ERP_CUSTOMER SET CustomerClass='Renuity East',CustomerClassDescription='Renuity East' WHERE CustomerClass IN ('FHIA');
UPDATE ZML.DIM_ERP_CUSTOMER SET CustomerClass='West Division',CustomerClassDescription='West Division' WHERE CustomerClass IN ('PACIFIC','Pacific Bath');

UPDATE ZML.[DIM_ERP_PROJECT] SET ProjectManager='FHIA',ProjectManagerDesc='FHIA FHIA' WHERE TRIM(ProjectManager) IN ('MAXHOME');
UPDATE ZML.[DIM_ERP_PROJECT] SET ProjectManager='RENUITY EAST',ProjectManagerDesc='RENUITY EAST' WHERE TRIM(ProjectManager) IN ('FHIA');
UPDATE ZML.[DIM_ERP_PROJECT] SET ProjectManager='WEST DIVISION',ProjectManagerDesc='WEST DIVISION' WHERE TRIM(ProjectManager) IN ('PACIFIC');
